import javax.imageio.ImageIO;
import java.awt.image.BufferedImage;
import java.io.IOException;
import java.io.InputStream;
import java.net.HttpURLConnection;
import java.net.InetAddress;
import java.net.MalformedURLException;
import java.net.URL;
import java.net.UnknownHostException;
import java.util.Arrays;
import java.util.HashSet;
import java.util.Set;

public class ImageService {

    private static final Set<String> ALLOWED_PROTOCOLS =
            new HashSet<>(Arrays.asList("http", "https"));
    private static final int CONNECTION_TIMEOUT_MS = 5000;
    private static final int READ_TIMEOUT_MS = 5000;

    public boolean processImageFromUrl(String imageUrl) {
        if (imageUrl == null || imageUrl.trim().isEmpty()) {
            return false;
        }

        try {
            URL url = new URL(imageUrl);

            // 1. 协议白名单
            if (!ALLOWED_PROTOCOLS.contains(url.getProtocol().toLowerCase())) {
                return false;
            }

            // 2. 主机名解析为 IP 并校验是否为内网或保留地址
            String host = url.getHost();
            if (host == null || host.trim().isEmpty()) {
                return false;
            }

            InetAddress[] addresses = InetAddress.getAllByName(host);
            for (InetAddress addr : addresses) {
                if (addr.isAnyLocalAddress() ||
                    addr.isLoopbackAddress() ||
                    addr.isLinkLocalAddress() ||
                    addr.isSiteLocalAddress()) {
                    return false;
                }
            }

            // 3. 禁止自动重定向
            HttpURLConnection conn = (HttpURLConnection) url.openConnection();
            try {
                conn.setInstanceFollowRedirects(false);
                conn.setRequestMethod("GET");
                conn.setConnectTimeout(CONNECTION_TIMEOUT_MS);
                conn.setReadTimeout(READ_TIMEOUT_MS);

                int status = conn.getResponseCode();
                if (status != HttpURLConnection.HTTP_OK) {
                    return false;
                }

                // 4. 验证 Content-Type（可选，加强校验）
                String contentType = conn.getContentType();
                if (contentType == null || !contentType.toLowerCase().startsWith("image/")) {
                    return false;
                }

                // 5. 读取图片内容并校验格式
                try (InputStream in = conn.getInputStream()) {
                    BufferedImage image = ImageIO.read(in);
                    return image != null;
                }
            } finally {
                conn.disconnect();
            }

        } catch (MalformedURLException | UnknownHostException e) {
            return false;
        } catch (IOException e) {
            return false;
        }
    }
}

