            BufferedImage image = ImageIO.read(connection.getInputStream());

            if (image != null) {
                System.out.println("Image processed successfully: " + image.getWidth() + "x" + image.getHeight());
                return true;
            }
        } catch (IOException e) {
            System.err.println("Error processing image from URL: " + e.getMessage());
        }
        return false;
    }

    private URL validateUrl(String urlString) throws IOException {
        if (urlString == null || urlString.trim().isEmpty()) {
            throw new IOException("URL cannot be null or empty");
